import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getReformAdvice(completedTasks: string[], segment: string) {
  const prompt = `
    LIXILのリフォームコンサルタントとして、以下の状況のユーザーに短いアドバイス（100文字程度）を日本語で提供してください。
    ユーザーの属性: ${segment === 'latent' ? '具体的に工事を検討中（顕在層）' : '情報収集を始めたばかり（準顕在層）'}
    完了したチェック項目: ${completedTasks.join(', ')}

    ユーザーが次に何をすべきか、LIXILの製品やサービス（ショールーム、オンライン相談、カタログなど）を交えて親身に提案してください。
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topK: 40,
        topP: 0.95,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "リフォームの第一歩、素晴らしいですね！次はショールームで実物を見てみませんか？";
  }
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  CheckCircle2, 
  ChevronRight, 
  HelpCircle, 
  Trophy, 
  MessageSquare,
  Sparkles,
  ArrowRight
} from 'lucide-react';
import { 
  COLORS, 
  GENERAL_CHECKLIST, 
  SEMI_LATENT_CHECKLIST, 
  LATENT_CHECKLIST, 
  DIAGNOSIS_QUESTIONS 
} from './constants';
import { UserSegment, ChecklistItem } from './types';
import { getReformAdvice } from './services/geminiService';

const App: React.FC = () => {
  const [segment, setSegment] = useState<UserSegment>('unknown');
  const [completedIds, setCompletedIds] = useState<string[]>([]);
  const [showDiagnosis, setShowDiagnosis] = useState(false);
  const [showGacha, setShowGacha] = useState(false);
  const [aiAdvice, setAiAdvice] = useState<string>('');
  const [isLoadingAdvice, setIsLoadingAdvice] = useState(false);

  // Combine lists based on segment
  const activeChecklist = useMemo(() => {
    let list = [...GENERAL_CHECKLIST];
    if (segment === 'semi-latent') {
      list = [...list, ...SEMI_LATENT_CHECKLIST];
    } else if (segment === 'latent') {
      list = [...list, ...LATENT_CHECKLIST];
    }
    return list;
  }, [segment]);

  const generalProgress = GENERAL_CHECKLIST.filter(item => completedIds.includes(item.id)).length;
  const segmentProgress = (segment === 'unknown') ? 0 : 
    (segment === 'semi-latent' ? SEMI_LATENT_CHECKLIST : LATENT_CHECKLIST)
    .filter(item => completedIds.includes(item.id)).length;

  const totalPossible = 3 + (segment === 'unknown' ? 0 : 3);
  const totalCompleted = completedIds.length;
  const isAllFinished = totalCompleted >= 6;

  // Handle checking items
  const toggleItem = (id: string) => {
    setCompletedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  // Trigger diagnosis after general checklist completion
  useEffect(() => {
    if (generalProgress === 3 && segment === 'unknown') {
      setShowDiagnosis(true);
    }
  }, [generalProgress, segment]);

  // Fetch AI advice when progress changes
  useEffect(() => {
    if (totalCompleted > 0) {
      const fetchAdvice = async () => {
        setIsLoadingAdvice(true);
        const titles = activeChecklist
          .filter(item => completedIds.includes(item.id))
          .map(item => item.title);
        const advice = await getReformAdvice(titles, segment);
        setAiAdvice(advice || '');
        setIsLoadingAdvice(false);
      };
      const debounce = setTimeout(fetchAdvice, 1000);
      return () => clearTimeout(debounce);
    }
  }, [completedIds, segment, activeChecklist]);

  const handleDiagnosisSubmit = (target: UserSegment) => {
    setSegment(target);
    setShowDiagnosis(false);
  };

  return (
    <div className="min-h-screen pb-24 text-gray-800">
      {/* Header */}
      <header className="bg-white px-6 py-4 shadow-sm flex items-center justify-between sticky top-0 z-40">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 bg-[#F36F21] rounded flex items-center justify-center">
            <span className="text-white font-bold text-xs">L</span>
          </div>
          <h1 className="text-lg font-bold tracking-tight text-[#F36F21]">LIXIL リフォームNavi</h1>
        </div>
        <div className="bg-gray-100 px-3 py-1 rounded-full text-xs font-medium text-gray-600">
          {segment === 'unknown' ? '準備中' : segment === 'latent' ? '具体検討中' : '情報収集中'}
        </div>
      </header>

      {/* Hero Section */}
      <section className="bg-white px-6 pt-6 pb-4">
        <div className="mb-4">
          <p className="text-xs text-orange-500 font-bold mb-1 uppercase tracking-wider">Step by Step</p>
          <h2 className="text-2xl font-bold leading-tight">
            理想の住まいへの<br />
            チェックリスト
          </h2>
        </div>

        {/* Progress Bar */}
        <div className="relative pt-1">
          <div className="flex mb-2 items-center justify-between">
            <div>
              <span className="text-xs font-semibold inline-block py-1 px-2 uppercase rounded-full text-orange-600 bg-orange-100">
                達成度: {Math.round((totalCompleted / 6) * 100)}%
              </span>
            </div>
            <div className="text-right">
              <span className="text-xs font-semibold inline-block text-orange-600">
                {totalCompleted}/6
              </span>
            </div>
          </div>
          <div className="overflow-hidden h-2 mb-4 text-xs flex rounded bg-orange-100">
            <div style={{ width: `${(totalCompleted / 6) * 100}%` }} className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-orange-500 transition-all duration-500"></div>
          </div>
        </div>
      </section>

      {/* Main Content */}
      <main className="px-6 space-y-8 mt-4">

        {/* General Checklist */}
        <div className="space-y-4">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center text-xs font-bold">1</div>
            <h3 className="font-bold text-lg">まずはここから！基本の準備</h3>
          </div>
          <div className="grid grid-cols-1 gap-4">
            {GENERAL_CHECKLIST.map(item => (
              <ChecklistCard 
                key={item.id}
                item={item} 
                completed={completedIds.includes(item.id)}
                onClick={() => toggleItem(item.id)}
              />
            ))}
          </div>
        </div>

        {/* AI Advice Box */}
        {aiAdvice && (
          <div className="bg-white border-l-4 border-orange-500 p-4 rounded-r-xl shadow-sm animate-fade-in">
            <div className="flex items-center gap-2 mb-2 text-orange-600">
              <Sparkles size={18} />
              <span className="text-sm font-bold">LIXIL AI アドバイザー</span>
            </div>
            <p className="text-sm leading-relaxed text-gray-700">
              {isLoadingAdvice ? '考え中...' : aiAdvice}
            </p>
          </div>
        )}

        {/* Segment Checklist */}
        {segment !== 'unknown' && (
          <div className="space-y-4 animate-slide-up">
            <div className="flex items-center gap-2">
              <div className="w-6 h-6 rounded-full bg-orange-100 text-orange-600 flex items-center justify-center text-xs font-bold">2</div>
              <h3 className="font-bold text-lg">
                {segment === 'latent' ? '夢を形に！具体的な検討' : 'もっと詳しく！理想の具体化'}
              </h3>
            </div>
            <div className="grid grid-cols-1 gap-4">
              {(segment === 'semi-latent' ? SEMI_LATENT_CHECKLIST : LATENT_CHECKLIST).map(item => (
                <ChecklistCard 
                  key={item.id}
                  item={item} 
                  completed={completedIds.includes(item.id)}
                  onClick={() => toggleItem(item.id)}
                />
              ))}
            </div>
          </div>
        )}

        {/* Locked State if segment is unknown */}
        {segment === 'unknown' && generalProgress < 3 && (
          <div className="p-8 bg-gray-100 rounded-2xl flex flex-col items-center justify-center text-center opacity-60">
            <HelpCircle size={40} className="text-gray-400 mb-3" />
            <p className="font-bold text-gray-500">まずは上の3項目を完了させて<br />診断をアンロックしましょう</p>
          </div>
        )}
      </main>

      {/* Floating Action Button for Gacha */}
      {isAllFinished && (
        <div className="fixed bottom-6 left-0 right-0 px-6 animate-bounce-subtle z-30">
          <button 
            onClick={() => setShowGacha(true)}
            className="w-full bg-[#F36F21] text-white py-4 rounded-full font-bold shadow-xl flex items-center justify-center gap-3 active:scale-95 transition-transform"
          >
            <Trophy />
            <span>すべての項目達成！ガチャを回す</span>
          </button>
        </div>
      )}

      {/* Diagnosis Modal */}
      {showDiagnosis && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-6 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-scale-in">
            <h3 className="text-xl font-bold mb-4 text-center">ステップ診断</h3>
            <p className="text-sm text-gray-600 mb-6 text-center">
              あなたの現在の状況に合わせて、<br />最適なチェックリストを表示します。
            </p>
            <div className="space-y-3">
              {DIAGNOSIS_QUESTIONS[0].options.map(option => (
                <button
                  key={option.id}
                  onClick={() => handleDiagnosisSubmit(option.targetSegment)}
                  className="w-full text-left p-4 rounded-xl border-2 border-gray-100 hover:border-orange-500 active:bg-orange-50 transition-colors group"
                >
                  <div className="flex items-center justify-between">
                    <span className="font-medium">{option.text}</span>
                    <ChevronRight size={18} className="text-gray-300 group-hover:text-orange-500" />
                  </div>
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Gacha Modal */}
      {showGacha && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-sm rounded-3xl p-8 text-center animate-scale-in">
            <div className="w-32 h-32 bg-orange-100 rounded-full flex items-center justify-center mx-auto mb-6 relative overflow-hidden">
               <Trophy size={60} className="text-orange-500" />
               <div className="absolute inset-0 bg-gradient-to-t from-white/20 to-transparent"></div>
            </div>
            <h3 className="text-2xl font-bold mb-2">コンプリート！</h3>
            <p className="text-gray-600 mb-8">
              おめでとうございます！リフォームの準備が完璧に整いました。特別なプレゼントを差し上げます。
            </p>
            <div className="bg-yellow-50 border-2 border-yellow-200 p-6 rounded-2xl mb-8">
              <div className="text-xs text-yellow-600 font-bold mb-1 uppercase tracking-widest">Your Reward</div>
              <div className="text-xl font-extrabold text-yellow-800">ショールームで使える<br />クオカード 1,000円分</div>
            </div>
            <button 
              onClick={() => setShowGacha(false)}
              className="w-full bg-gray-900 text-white py-4 rounded-xl font-bold"
            >
              特典を受け取る
            </button>
          </div>
        </div>
      )}

      <style>{`
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scale-in { from { transform: scale(0.9); opacity: 0; } to { transform: scale(1); opacity: 1; } }
        @keyframes slide-up { from { transform: translateY(20px); opacity: 0; } to { transform: translateY(0); opacity: 1; } }
        @keyframes bounce-subtle { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-5px); } }
        .animate-fade-in { animation: fade-in 0.4s ease-out; }
        .animate-scale-in { animation: scale-in 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
        .animate-slide-up { animation: slide-up 0.5s ease-out; }
        .animate-bounce-subtle { animation: bounce-subtle 2s infinite ease-in-out; }
      `}</style>
    </div>
  );
};

interface ChecklistCardProps {
  item: ChecklistItem;
  completed: boolean;
  onClick: () => void;
}

const ChecklistCard: React.FC<ChecklistCardProps> = ({ item, completed, onClick }) => {
  return (
    <div 
      onClick={onClick}
      className={`relative p-5 rounded-2xl border-2 transition-all duration-300 cursor-pointer active:scale-[0.98] ${
        completed 
          ? 'bg-white border-orange-500 shadow-md ring-4 ring-orange-50' 
          : 'bg-white border-gray-100 hover:border-gray-200'
      }`}
    >
      <div className="flex gap-4">
        <div className={`mt-1 flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-colors ${
          completed ? 'bg-orange-500 border-orange-500' : 'border-gray-300 bg-white'
        }`}>
          {completed && <CheckCircle2 size={16} className="text-white" />}
        </div>
        <div className="flex-1">
          <h4 className={`font-bold text-sm mb-1 ${completed ? 'text-gray-900' : 'text-gray-700'}`}>
            {item.title}
          </h4>
          <p className="text-xs text-gray-500 leading-relaxed">
            {item.description}
          </p>
        </div>
        {!completed && (
           <div className="flex items-center text-gray-300">
             <ChevronRight size={20} />
           </div>
        )}
      </div>

      {/* Stamp Effect when completed */}
      {completed && (
        <div className="absolute top-2 right-2 opacity-10 rotate-12 pointer-events-none">
          <CheckCircle2 size={60} />
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  CheckCircle2, 
  ChevronRight, 
  HelpCircle, 
  Trophy, 
  ArrowRight,
  ChevronLeft
} from 'lucide-react';
import { 
  GENERAL_CHECKLIST, 
  SEMI_LATENT_CHECKLIST, 
  LATENT_CHECKLIST, 
  DIAGNOSIS_QUESTIONS 
} from './constants';
import { UserSegment, ChecklistItem } from './types';

type ViewState = 'step1' | 'step2';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('step1');
  const [segment, setSegment] = useState<UserSegment>('unknown');
  const [completedIds, setCompletedIds] = useState<string[]>([]);
  const [showDiagnosis, setShowDiagnosis] = useState(false);
  const [showGacha, setShowGacha] = useState(false);

  // 完了状況の計算
  const generalCompletedCount = GENERAL_CHECKLIST.filter(item => completedIds.includes(item.id)).length;
  const isStep1Finished = generalCompletedCount === 3;

  const segmentChecklist = useMemo(() => {
    if (segment === 'semi-latent') return SEMI_LATENT_CHECKLIST;
    if (segment === 'latent') return LATENT_CHECKLIST;
    return [];
  }, [segment]);

  const segmentCompletedCount = segmentChecklist.filter(item => completedIds.includes(item.id)).length;
  const isStep2Finished = segmentCompletedCount === 3;
  const isAllFinished = isStep1Finished && isStep2Finished;

  // チェック項目のトグル
  const toggleItem = (id: string) => {
    setCompletedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleDiagnosisSubmit = (target: UserSegment) => {
    setSegment(target);
    setShowDiagnosis(false);
    setView('step2');
  };

  const goToStep2 = () => {
    if (segment === 'unknown') {
      setShowDiagnosis(true);
    } else {
      setView('step2');
    }
  };

  return (
    <div className="min-h-screen pb-24 text-gray-800 bg-[#F8F9FA]">
      {/* Header */}
      <header className="bg-white px-6 py-4 shadow-sm flex items-center justify-between sticky top-0 z-40">
        <div className="flex items-center gap-2">
          {view === 'step2' && (
            <button onClick={() => setView('step1')} className="mr-1 p-1 -ml-2 text-gray-400 hover:text-gray-600">
              <ChevronLeft size={24} />
            </button>
          )}
          <div className="w-8 h-8 bg-[#F36F21] rounded flex items-center justify-center shrink-0">
            <span className="text-white font-bold text-xs">L</span>
          </div>
          <h1 className="text-lg font-bold tracking-tight text-[#F36F21] truncate">LIXIL リフォームNavi</h1>
        </div>
        <div className="bg-orange-50 px-3 py-1 rounded-full text-[10px] font-bold text-orange-600 whitespace-nowrap">
          {view === 'step1' ? 'STEP 1/2' : 'STEP 2/2'}
        </div>
      </header>

      {/* Progress Bar Area */}
      <div className="bg-white px-6 pb-4">
        <div className="flex justify-between items-end mb-2">
          <h2 className="text-xl font-bold leading-tight">
            {view === 'step1' ? 'まずはここから！\n基本の準備' : 'あなたにぴったりの\nリフォーム検討'}
          </h2>
          <div className="text-right">
            <span className="text-xs font-bold text-orange-600">
              {view === 'step1' ? `${generalCompletedCount}/3` : `${segmentCompletedCount}/3`}
            </span>
          </div>
        </div>
        <div className="overflow-hidden h-2 flex rounded bg-orange-100">
          <div 
            style={{ width: `${view === 'step1' ? (generalCompletedCount / 3) * 100 : (segmentCompletedCount / 3) * 100}%` }} 
            className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-orange-500 transition-all duration-500"
          ></div>
        </div>
      </div>

      {/* Main Content */}
      <main className="px-6 mt-6">
        {view === 'step1' ? (
          <div className="space-y-4 animate-fade-in">
            <p className="text-sm text-gray-500 mb-4">
              理想のリフォームを実現するために、まずは土台となる3つのステップをクリアしましょう。
            </p>
            <div className="grid grid-cols-1 gap-4">
              {GENERAL_CHECKLIST.map(item => (
                <ChecklistCard 
                  key={item.id}
                  item={item} 
                  completed={completedIds.includes(item.id)}
                  onClick={() => toggleItem(item.id)}
                />
              ))}
            </div>

            {isStep1Finished && (
              <div className="pt-6 animate-bounce-subtle">
                <button 
                  onClick={goToStep2}
                  className="w-full bg-[#F36F21] text-white py-4 rounded-2xl font-bold shadow-lg flex items-center justify-center gap-2"
                >
                  <span>{segment === 'unknown' ? '自分に合った診断へ進む' : '次のステップへ'}</span>
                  <ArrowRight size={20} />
