import React, { useState, useMemo } from 'react';
import { 
  CheckCircle2, 
  ChevronRight, 
  HelpCircle, 
  Trophy, 
  ArrowRight,
  ChevronLeft
} from 'lucide-react';
import { 
  GENERAL_CHECKLIST, 
  SEMI_LATENT_CHECKLIST, 
  LATENT_CHECKLIST, 
  DIAGNOSIS_QUESTIONS 
} from './constants';
import { UserSegment, ChecklistItem } from './types';

type ViewState = 'step1' | 'step2';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('step1');
  const [segment, setSegment] = useState<UserSegment>('unknown');
  const [completedIds, setCompletedIds] = useState<string[]>([]);
  const [showDiagnosis, setShowDiagnosis] = useState(false);
  const [currentDiagnosisIndex, setCurrentDiagnosisIndex] = useState(0);
  const [diagnosisAnswers, setDiagnosisAnswers] = useState<UserSegment[]>([]);
  const [showGacha, setShowGacha] = useState(false);

  // 完了状況の計算
  const generalCompletedCount = GENERAL_CHECKLIST.filter(item => completedIds.includes(item.id)).length;
  const isStep1Finished = generalCompletedCount === 3;

  const segmentChecklist = useMemo(() => {
    if (segment === 'semi-latent') return SEMI_LATENT_CHECKLIST;
    if (segment === 'latent') return LATENT_CHECKLIST;
    return [];
  }, [segment]);

  const segmentCompletedCount = segmentChecklist.filter(item => completedIds.includes(item.id)).length;
  const isStep2Finished = segmentCompletedCount === 3;
  const isAllFinished = isStep1Finished && isStep2Finished;

  // チェック項目のトグル
  const toggleItem = (id: string) => {
    setCompletedIds(prev => 
      prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]
    );
  };

  const handleDiagnosisOptionClick = (target: UserSegment) => {
    const newAnswers = [...diagnosisAnswers, target];
    setDiagnosisAnswers(newAnswers);

    if (currentDiagnosisIndex < DIAGNOSIS_QUESTIONS.length - 1) {
      setCurrentDiagnosisIndex(prev => prev + 1);
    } else {
      // 最終判定: 多数決ロジック
      const latentCount = newAnswers.filter(a => a === 'latent').length;
      const finalSegment = latentCount >= 2 ? 'latent' : 'semi-latent';

      setSegment(finalSegment);
      setShowDiagnosis(false);
      setView('step2');
    }
  };

  const goToStep2 = () => {
    if (segment === 'unknown') {
      setCurrentDiagnosisIndex(0);
      setDiagnosisAnswers([]);
      setShowDiagnosis(true);
    } else {
      setView('step2');
    }
  };

  return (
    <div className="min-h-screen pb-24 text-gray-800 bg-[#F8F9FA]">
      {/* Header */}
      <header className="bg-white px-6 py-4 shadow-sm flex items-center justify-between sticky top-0 z-40">
        <div className="flex items-center gap-2">
          {view === 'step2' && (
            <button onClick={() => setView('step1')} className="mr-1 p-1 -ml-2 text-gray-400 hover:text-gray-600">
              <ChevronLeft size={24} />
            </button>
          )}
          <div className="w-8 h-8 bg-[#F36F21] rounded flex items-center justify-center shrink-0">
            <span className="text-white font-bold text-xs">L</span>
          </div>
          <h1 className="text-lg font-bold tracking-tight text-[#F36F21] truncate">LIXIL リフォームNavi</h1>
        </div>
        <div className="bg-orange-50 px-3 py-1 rounded-full text-[10px] font-bold text-orange-600 whitespace-nowrap">
          {view === 'step1' ? 'STEP 1/2' : 'STEP 2/2'}
        </div>
      </header>

      {/* Progress Bar Area */}
      <div className="bg-white px-6 pb-4">
        <div className="flex justify-between items-end mb-2">
          <h2 className="text-xl font-bold leading-tight">
            {view === 'step1' ? 'まずはここから！\n基本の準備' : 'あなたにぴったりの\nリフォーム検討'}
          </h2>
          <div className="text-right">
            <span className="text-xs font-bold text-orange-600">
              {view === 'step1' ? `${generalCompletedCount}/3` : `${segmentCompletedCount}/3`}
            </span>
          </div>
        </div>
        <div className="overflow-hidden h-2 flex rounded bg-orange-100">
          <div 
            style={{ width: `${view === 'step1' ? (generalCompletedCount / 3) * 100 : (segmentCompletedCount / 3) * 100}%` }} 
            className="shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center bg-orange-500 transition-all duration-500"
          ></div>
        </div>
      </div>

      {/* Main Content */}
      <main className="px-6 mt-6">
        {view === 'step1' ? (
          <div className="space-y-4 animate-fade-in">
            <p className="text-sm text-gray-500 mb-4">
              理想のリフォームを実現するために、まずは土台となる3つのステップをクリアしましょう。
            </p>
            <div className="grid grid-cols-1 gap-4">
              {GENERAL_CHECKLIST.map(item => (
                <ChecklistCard 
                  key={item.id}
                  item={item} 
                  completed={completedIds.includes(item.id)}
                  onClick={() => toggleItem(item.id)}
                />
              ))}
            </div>

            {isStep1Finished && (
              <div className="pt-6 animate-bounce-subtle">
                <button 
                  onClick={goToStep2}
                  className="w-full bg-[#F36F21] text-white py-4 rounded-2xl font-bold shadow-lg flex items-center justify-center gap-2"
                >
                  <span>{segment === 'unknown' ? 'ピッタリ診断へ進む' : '次のステップへ'}</span>
                  <ArrowRight size={20} />
                </button>
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-4 animate-fade-in">
            <div className="bg-white p-4 rounded-2xl border border-orange-100 mb-6 flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-orange-50 flex items-center justify-center text-orange-500 shrink-0">
                <HelpCircle size={20} />
              </div>
              <p className="text-xs font-medium text-gray-600 leading-snug">
                診断結果に基づいた、今のあなたに最適なアクションプランです。
              </p>
            </div>

            <div className="grid grid-cols-1 gap-4">
              {segmentChecklist.map(item => (
                <ChecklistCard 
                  key={item.id}
                  item={item} 
                  completed={completedIds.includes(item.id)}
                  onClick={() => toggleItem(item.id)}
                />
              ))}
            </div>

            {!isStep2Finished && (
              <p className="text-center text-xs text-gray-400 mt-8">
                すべてのチェックを完了させると、<br />特別なガチャに挑戦できます。
              </p>
            )}
          </div>
        )}
      </main>

      {/* Floating Action Button for Gacha */}
      {isAllFinished && view === 'step2' && (
        <div className="fixed bottom-6 left-0 right-0 px-6 animate-bounce-subtle z-30">
          <button 
            onClick={() => setShowGacha(true)}
            className="w-full bg-gray-900 text-white py-4 rounded-full font-bold shadow-xl flex items-center justify-center gap-3 active:scale-95 transition-transform"
          >
            <Trophy className="text-yellow-400" />
            <span>コンプリートガチャを回す</span>
          </button>
        </div>
      )}

      {/* Diagnosis Modal (Multi-step) */}
      {showDiagnosis && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-6 backdrop-blur-sm">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 shadow-2xl animate-scale-in">
            <div className="flex justify-between items-center mb-6">
               <div className="text-[10px] font-bold bg-gray-100 text-gray-400 px-2 py-0.5 rounded-full">
                 Q {currentDiagnosisIndex + 1} / {DIAGNOSIS_QUESTIONS.length}
               </div>
               <div className="flex gap-1">
                 {DIAGNOSIS_QUESTIONS.map((_, i) => (
                   <div 
                    key={i} 
                    className={`h-1 w-4 rounded-full transition-all duration-300 ${i <= currentDiagnosisIndex ? 'bg-orange-500' : 'bg-gray-100'}`}
                   />
                 ))}
               </div>
            </div>

            <h3 className="text-lg font-bold mb-6 text-center leading-tight min-h-[3rem]">
              {DIAGNOSIS_QUESTIONS[currentDiagnosisIndex].question}
            </h3>

            <div className="space-y-3">
              {DIAGNOSIS_QUESTIONS[currentDiagnosisIndex].options.map(option => (
                <button
                  key={option.id}
                  onClick={() => handleDiagnosisOptionClick(option.targetSegment)}
                  className="w-full text-left p-4 rounded-xl border-2 border-gray-100 hover:border-orange-500 active:bg-orange-50 transition-colors group flex items-center justify-between"
                >
                  <span className="font-bold text-sm text-gray-700">{option.text}</span>
                  <ChevronRight size={18} className="text-gray-300 group-hover:text-orange-500 shrink-0 ml-2" />
                </button>
              ))}
            </div>

            {currentDiagnosisIndex > 0 && (
              <button 
                onClick={() => {
                  setCurrentDiagnosisIndex(prev => prev - 1);
                  setDiagnosisAnswers(prev => prev.slice(0, -1));
                }}
                className="mt-6 w-full text-center text-xs text-gray-400 font-medium py-2"
              >
                前の質問に戻る
              </button>
            )}
          </div>
        </div>
      )}

      {/* Gacha Modal */}
      {showGacha && (
        <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-6">
          <div className="bg-white w-full max-w-sm rounded-3xl p-8 text-center animate-scale-in">
            <div className="w-32 h-32 bg-orange-100 rounded-full flex items-center justify-center mx-auto mb-6 relative overflow-hidden">
               <Trophy size={60} className="text-orange-500" />
               <div className="absolute inset-0 bg-gradient-to-t from-white/20 to-transparent"></div>
            </div>
            <h3 className="text-2xl font-bold mb-2 text-[#F36F21]">おめでとうございます！</h3>
            <p className="text-gray-600 mb-8 text-sm leading-relaxed">
              すべてのステップを達成しました！<br />あなたの理想の住まいづくりを応援します。
            </p>
            <div className="bg-yellow-50 border-2 border-yellow-200 p-6 rounded-2xl mb-8 relative">
              <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-yellow-400 text-white text-[10px] px-2 py-0.5 rounded-full font-bold uppercase">Reward</div>
              <div className="text-lg font-extrabold text-yellow-800">ショールームで使える<br />クオカード 1,000円分</div>
            </div>
            <button 
              onClick={() => setShowGacha(false)}
              className="w-full bg-[#F36F21] text-white py-4 rounded-xl font-bold shadow-lg"
            >
              特典を受け取って終了
            </button>
          </div>
        </div>
      )}

      <style>{`
        @keyframes fade-in { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes scale-in { from { transform: scale(0.9); opacity: 0; } to { transform: scale(1); opacity: 1; } }
        @keyframes bounce-subtle { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-5px); } }
        .animate-fade-in { animation: fade-in 0.4s ease-out; }
        .animate-scale-in { animation: scale-in 0.3s cubic-bezier(0.34, 1.56, 0.64, 1); }
        .animate-bounce-subtle { animation: bounce-subtle 2s infinite ease-in-out; }
      `}</style>
    </div>
  );
