          {completed && <CheckCircle2 size={16} className="text-white" />}
        </div>
        <div className="flex-1">
          <h4 className={`font-bold text-[15px] mb-1 ${completed ? 'text-gray-900' : 'text-gray-700'}`}>
            {item.title}
          </h4>
          <p className="text-xs text-gray-400 leading-relaxed font-medium">
            {item.description}
          </p>
        </div>
      </div>

      {/* Stamp Effect when completed */}
      {completed && (
        <div className="absolute top-2 right-2 opacity-5 rotate-12 pointer-events-none text-orange-600">
          <CheckCircle2 size={64} strokeWidth={1} />
        </div>
      )}
    </div>
  );
};

