      </div>

      {/* Stamp Effect when completed */}
      {completed && (
        <div className="absolute top-2 right-2 opacity-5 rotate-12 pointer-events-none text-orange-600">
          <CheckCircle2 size={64} strokeWidth={1} />
        </div>
      )}
